int main() {
   WeightNode* headWeight = nullptr;  // The head node
   WeightNode* currWeight = nullptr;  // Used to traverse the linked list and create new nodes
   WeightNode* lastWeight = nullptr;  // Points to the last node in the list
   int count;  // The number of weights to be input
   int inputValue;  // Temporary variable to hold each input weight

   cin >> count;

   // Create the head node to store the number of weights (not an actual weight value)
   headWeight = new WeightNode(count);
   // Last node is the head node initially
   lastWeight = headWeight;

   // Read weights and build the linked list
   for (int i = 0; i < count; ++i) {
      cin >> inputValue;     
      currWeight = new WeightNode(inputValue);     
      lastWeight->InsertAfter(currWeight);
      lastWeight = currWeight;
   }

   // Traverse the linked list starting from the node after headWeight to find negative integers
   currWeight = headWeight->GetNext();  // Skipping the head node as it contains the count
   while (currWeight != nullptr) {
      if (currWeight->GetNodeData() < 0) {
         cout << currWeight->GetNodeData() << " is flagged as invalid." << endl;
      }
      currWeight = currWeight->GetNext();
   }

   // Free the dynamically allocated memory
   currWeight = headWeight;
   WeightNode* nextWeight;
   while (currWeight != nullptr) {
      nextWeight = currWeight->GetNext();
      delete currWeight;  // Free the current node
      currWeight = nextWeight;  // Move to the next node
   }

   return 0;
}
